printf(
				'<p>%s</p>',
				sprintf(
					// translators: %s: The URL to the Debugging in WordPress article.
					__( 'You can read more about the <code>WP_DEBUG_LOG</code> constant, and how to enable it, in the <a href="%s">Debugging in WordPress</a> article.', 'health-check' ),
					// translators: The localized URL to the Debugging in WordPress article, if available.
					__( 'https://wordpress.org/documentation/article/debugging-in-wordpress/#wp_debug_log', 'health-check' )
				)
			)

printf(
			'<div class="notice notice-warning dismissable"><p>%s</p><p><a href="%s" class="button button-primary">%s</a> <a href="%s" class="button button-secondary">%s</a></p></div>',
			esc_html__( 'You don\'t have any of the default themes installed. A default theme helps you determine if your current theme is causing conflicts.', 'health-check' ),
			esc_url(
				admin_url(
					sprintf(
						'theme-install.php?theme=%s',
						$this->default_themes[0]
					)
				)
			),
			esc_html__( 'Install the latest default theme', 'health-check' ),
			esc_url(
				admin_url(
					sprintf(
						'theme-install.php?theme=%s',
						$this->latest_classic_default_theme
					)
				)
			),
			esc_html__( 'Install the latest classic default theme', 'health-check' )
		)

printf(
								// translators: %s: The running status of Troubleshooting Mode.
								esc_html__( 'Troubleshooting Mode - %s', 'health-check' ),
								sprintf(
									'<span class="green">%s</span>',
									esc_html__( 'enabled', 'health-check' )
								)
							)

printf(
						'<a href="%s" class="button button-primary">%s</a>',
						esc_url(
							add_query_arg(
								array(
									'health-check-disable-troubleshooting' => true,
									'_wpnonce' => $this->prepare_action_nonce( 'health-check-disable-troubleshooting', array() ),
								),
								$this->get_clean_url()
							)
						),
						esc_html__( 'Disable Troubleshooting Mode', 'health-check' )
					)

printf(
										// translators: %d: The amount of available plugins.
										esc_html__( 'Available plugins (%d)', 'health-check' ),
										esc_html( is_countable( $this->active_plugins ) ? count( $this->active_plugins ) : 0 )
									)

printf(
											'<li><button type="button" class="show-remaining button button-link">%s</button></li>',
											sprintf(
												// translators: %d: Amount of hidden plugins.
												_n(
													'Show %d remaining plugin',
													'Show %d remaining plugins',
													( is_countable( $this->active_plugins ) ? ( count( $this->active_plugins ) - 5 ) : 0 ),
													'health-check'
												),
												( is_countable( $this->active_plugins ) ? ( count( $this->active_plugins ) - 5 ) : 0 )
											)
										)

printf(
										// translators: %d: The amount of available themes.
										esc_html__( 'Available themes (%d)', 'health-check' ),
										esc_html( is_countable( $themes ) ? count( $themes ) : 0 )
									)

printf(
											'<li><button type="button" class="show-remaining button button-link">%s</button></li>',
											sprintf(
												// translators: %d: Amount of hidden themes.
												_n(
													'Show %d remaining theme',
													'Show %d remaining themes',
													( is_countable( $themes ) ? ( count( $themes ) - 5 ) : 0 ),
													'health-check'
												),
												( is_countable( $themes ) ? ( count( $themes ) - 5 ) : 0 )
											)
										)

printf(
										// translators: %d: The amount of notices that are visible.
										esc_html__( 'Notices (%d)', 'health-check' ),
										esc_html( is_countable( $notices ) ? count( $notices ) : 0 )
									)

printf(
									'<div class="dismiss-notices"><a href="%s" class="">%s</a></div>',
									esc_url(
										add_query_arg(
											array(
												'health-check-dismiss-notices' => true,
												'_wpnonce' => $this->prepare_action_nonce( 'health-check-dismiss-notices', array() ),
											),
											$this->get_clean_url()
										)
									),
									esc_html__( 'Dismiss notices', 'health-check' )
								)

printf(
			/* translators: %s: The label of the "Take screenshot" button. */
			esc_html__( 'To take a screenshot for sharing with support users, you may click the %s button, found at the top of every page, and they will be stored securely on your site until you wish to share them.', 'health-check' ),
			sprintf(
				'<strong>%s</strong>',
				esc_html_x( 'Take Screenshot', 'Description of the button label', 'health-check' )
			)
		)

printf(
			// translators: %s: The current WordPress version used on this site.
			__( 'You are running an older version of WordPress, version %s. The Site Health features from this plugin were added to version 5.2 of WordPress.', 'health-check' ),
			get_bloginfo( 'version' )
		)

